{"language": "html", "code": "<!DOCTYPE html>
<html lang="ko">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Lovable × HR — AX 실습 교재</title>
<link href="https://fonts.googleapis.com/css2?family=Noto+Serif+KR:wght@400;700;900&family=DM+Mono:wght@400;500&family=Pretendard:wght@300;400;500;600;700&display=swap" rel="stylesheet">
<style>
  :root {
    --bg: #0d0d0f;
    --surface: #141417;
    --surface2: #1c1c21;
    --border: #2a2a32;
    --accent: #e8ff47;
    --accent2: #47c8ff;
    --accent3: #ff6b6b;
    --text: #f0f0f4;
    --muted: #7a7a8c;
    --tag-bg: #1e1e28;
  }

  * { margin: 0; padding: 0; box-sizing: border-box; }

  body {
    background: var(--bg);
    color: var(--text);
    font-family: 'Pretendard', sans-serif;
    line-height: 1.6;
    min-height: 100vh;
  }

  /* ── HEADER ── */
  .header {
    padding: 60px 40px 40px;
    border-bottom: 1px solid var(--border);
    position: relative;
    overflow: hidden;
  }
  .header::before {
    content: '';
    position: absolute;
    top: -80px; right: -80px;
    width: 400px; height: 400px;
    background: radial-gradient(circle, rgba(232,255,71,0.07) 0%, transparent 70%);
    pointer-events: none;
  }
  .header-tag {
    display: inline-block;
    background: var(--accent);
    color: #0d0d0f;
    font-size: 11px;
    font-weight: 700;
    letter-spacing: 2px;
    text-transform: uppercase;
    padding: 4px 12px;
    margin-bottom: 20px;
  }
  .header h1 {
    font-family: 'Noto Serif KR', serif;
    font-size: clamp(28px, 5vw, 52px);
    font-weight: 900;
    line-height: 1.15;
    max-width: 700px;
  }
  .header h1 span { color: var(--accent); }
  .header-sub {
    margin-top: 16px;
    color: var(--muted);
    font-size: 15px;
    max-width: 560px;
  }
  .header-meta {
    margin-top: 32px;
    display: flex;
    gap: 24px;
    flex-wrap: wrap;
  }
  .meta-chip {
    display: flex;
    align-items: center;
    gap: 8px;
    font-size: 13px;
    color: var(--muted);
  }
  .meta-chip .dot {
    width: 6px; height: 6px;
    border-radius: 50%;
    background: var(--accent);
  }

  /* ── MAIN LAYOUT ── */
  .container {
    display: grid;
    grid-template-columns: 280px 1fr;
    min-height: calc(100vh - 200px);
  }

  /* ── SIDEBAR ── */
  .sidebar {
    border-right: 1px solid var(--border);
    padding: 32px 24px;
    position: sticky;
    top: 0;
    height: calc(100vh - 200px);
    overflow-y: auto;
  }
  .sidebar-label {
    font-size: 10px;
    letter-spacing: 2px;
    text-transform: uppercase;
    color: var(--muted);
    margin-bottom: 16px;
    font-weight: 600;
  }
  .mission-card {
    background: var(--surface2);
    border: 1px solid var(--border);
    border-radius: 4px;
    padding: 16px;
    margin-bottom: 24px;
  }
  .mission-card .title {
    font-size: 12px;
    font-weight: 600;
    color: var(--accent);
    margin-bottom: 8px;
  }
  .mission-card p {
    font-size: 13px;
    color: var(--muted);
    line-height: 1.5;
  }

  .task-nav {
    display: flex;
    flex-direction: column;
    gap: 4px;
  }
  .task-btn {
    display: flex;
    align-items: center;
    gap: 10px;
    padding: 10px 12px;
    border-radius: 4px;
    border: 1px solid transparent;
    background: transparent;
    color: var(--muted);
    font-size: 13px;
    cursor: pointer;
    text-align: left;
    transition: all 0.2s;
    font-family: 'Pretendard', sans-serif;
  }
  .task-btn:hover {
    background: var(--surface2);
    color: var(--text);
    border-color: var(--border);
  }
  .task-btn.active {
    background: var(--surface2);
    color: var(--accent);
    border-color: var(--accent);
  }
  .task-btn .num {
    font-family: 'DM Mono', monospace;
    font-size: 11px;
    width: 20px;
  }
  .task-btn .check {
    margin-left: auto;
    font-size: 12px;
    color: var(--accent);
    display: none;
  }
  .task-btn.done .check { display: block; }
  .task-btn.done .num { color: var(--accent); }

  /* ── CONTENT AREA ── */
  .content {
    padding: 40px;
    max-width: 900px;
  }

  /* ── TASK SELECTOR ── */
  .task-selector {
    display: none;
  }
  .task-selector.active {
    display: block;
  }

  /* ── OVERVIEW ── */
  .overview-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(200px, 1fr));
    gap: 16px;
    margin-bottom: 48px;
  }
  .overview-card {
    background: var(--surface);
    border: 1px solid var(--border);
    border-radius: 4px;
    padding: 20px;
    cursor: pointer;
    transition: all 0.2s;
    position: relative;
    overflow: hidden;
  }
  .overview-card::after {
    content: '';
    position: absolute;
    bottom: 0; left: 0;
    height: 2px; width: 0;
    background: var(--accent);
    transition: width 0.3s;
  }
  .overview-card:hover {
    border-color: var(--accent);
    transform: translateY(-2px);
  }
  .overview-card:hover::after { width: 100%; }
  .overview-card .card-num {
    font-family: 'DM Mono', monospace;
    font-size: 11px;
    color: var(--accent);
    margin-bottom: 10px;
  }
  .overview-card .card-title {
    font-size: 14px;
    font-weight: 600;
    line-height: 1.4;
    margin-bottom: 8px;
  }
  .overview-card .card-time {
    font-size: 12px;
    color: var(--muted);
  }
  .overview-card .card-emoji {
    font-size: 28px;
    margin-bottom: 12px;
  }

  /* ── TASK DETAIL ── */
  .task-detail { display: none; }
  .task-detail.active { display: block; }

  .task-header {
    margin-bottom: 40px;
    padding-bottom: 24px;
    border-bottom: 1px solid var(--border);
  }
  .task-header .back-btn {
    display: inline-flex;
    align-items: center;
    gap: 6px;
    font-size: 12px;
    color: var(--muted);
    cursor: pointer;
    margin-bottom: 20px;
    background: none;
    border: none;
    font-family: 'Pretendard', sans-serif;
    transition: color 0.2s;
  }
  .task-header .back-btn:hover { color: var(--text); }
  .task-header .task-badge {
    display: inline-block;
    background: var(--tag-bg);
    border: 1px solid var(--border);
    font-size: 11px;
    color: var(--accent2);
    padding: 3px 10px;
    border-radius: 2px;
    margin-bottom: 12px;
    font-family: 'DM Mono', monospace;
  }
  .task-header h2 {
    font-family: 'Noto Serif KR', serif;
    font-size: 28px;
    font-weight: 700;
    margin-bottom: 10px;
  }
  .task-header p {
    color: var(--muted);
    font-size: 15px;
  }

  /* ── STEP FLOW ── */
  .step-flow {
    display: flex;
    align-items: center;
    gap: 0;
    margin-bottom: 40px;
    overflow-x: auto;
    padding-bottom: 8px;
  }
  .step-pill {
    display: flex;
    align-items: center;
    gap: 8px;
    padding: 8px 16px;
    background: var(--surface2);
    border: 1px solid var(--border);
    border-radius: 2px;
    font-size: 12px;
    cursor: pointer;
    transition: all 0.2s;
    white-space: nowrap;
    font-family: 'Pretendard', sans-serif;
    color: var(--muted);
  }
  .step-pill.active {
    background: var(--accent);
    color: #0d0d0f;
    border-color: var(--accent);
    font-weight: 600;
  }
  .step-pill.done {
    border-color: var(--accent);
    color: var(--accent);
  }
  .step-arrow {
    font-size: 12px;
    color: var(--border);
    padding: 0 4px;
    flex-shrink: 0;
  }

  /* ── STEP CONTENT ── */
  .step-content { display: none; }
  .step-content.active { display: block; }

  .step-block {
    background: var(--surface);
    border: 1px solid var(--border);
    border-radius: 4px;
    padding: 32px;
    margin-bottom: 20px;
  }
  .step-block .step-num {
    font-family: 'DM Mono', monospace;
    font-size: 11px;
    color: var(--accent);
    letter-spacing: 1px;
    margin-bottom: 12px;
  }
  .step-block h3 {
    font-size: 20px;
    font-weight: 700;
    margin-bottom: 12px;
  }
  .step-block p {
    color: var(--muted);
    font-size: 14px;
    line-height: 1.7;
    margin-bottom: 16px;
  }

  /* ── PROMPT BOX ── */
  .prompt-box {
    background: #0a0a0c;
    border: 1px solid var(--accent);
    border-radius: 4px;
    overflow: hidden;
    margin: 20px 0;
  }
  .prompt-box-header {
    background: var(--accent);
    padding: 8px 16px;
    display: flex;
    align-items: center;
    justify-content: space-between;
  }
  .prompt-box-header .label {
    font-size: 11px;
    font-weight: 700;
    color: #0d0d0f;
    letter-spacing: 1px;
    text-transform: uppercase;
    font-family: 'DM Mono', monospace;
  }
  .copy-btn {
    background: rgba(0,0,0,0.15);
    border: none;
    color: #0d0d0f;
    font-size: 11px;
    font-weight: 600;
    padding: 3px 10px;
    border-radius: 2px;
    cursor: pointer;
    font-family: 'DM Mono', monospace;
    transition: background 0.2s;
  }
  .copy-btn:hover { background: rgba(0,0,0,0.3); }
  .copy-btn.copied { background: #0d0d0f; color: var(--accent); }
  .prompt-text {
    padding: 20px;
    font-family: 'DM Mono', monospace;
    font-size: 13px;
    line-height: 1.8;
    color: #c8ffa0;
    white-space: pre-wrap;
    word-break: break-word;
  }

  /* ── INFO BOX ── */
  .info-box {
    border-left: 3px solid var(--accent2);
    background: rgba(71, 200, 255, 0.05);
    padding: 16px 20px;
    border-radius: 0 4px 4px 0;
    margin: 16px 0;
  }
  .info-box .info-label {
    font-size: 11px;
    font-weight: 700;
    color: var(--accent2);
    letter-spacing: 1px;
    text-transform: uppercase;
    margin-bottom: 6px;
  }
  .info-box p { color: var(--muted); font-size: 13px; margin: 0; }

  .warn-box {
    border-left: 3px solid var(--accent3);
    background: rgba(255,107,107,0.05);
    padding: 16px 20px;
    border-radius: 0 4px 4px 0;
    margin: 16px 0;
  }
  .warn-box .warn-label {
    font-size: 11px;
    font-weight: 700;
    color: var(--accent3);
    letter-spacing: 1px;
    text-transform: uppercase;
    margin-bottom: 6px;
  }
  .warn-box p { color: var(--muted); font-size: 13px; margin: 0; }

  /* ── CHECKLIST ── */
  .checklist {
    list-style: none;
    margin: 16px 0;
  }
  .checklist li {
    display: flex;
    align-items: flex-start;
    gap: 10px;
    padding: 8px 0;
    font-size: 14px;
    color: var(--muted);
    border-bottom: 1px solid var(--border);
    cursor: pointer;
    transition: color 0.2s;
  }
  .checklist li:last-child { border-bottom: none; }
  .checklist li .cb {
    width: 16px; height: 16px;
    border: 1px solid var(--border);
    border-radius: 2px;
    flex-shrink: 0;
    margin-top: 2px;
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 10px;
    transition: all 0.2s;
  }
  .checklist li.checked { color: var(--text); }
  .checklist li.checked .cb {
    background: var(--accent);
    border-color: var(--accent);
    color: #0d0d0f;
  }

  /* ── MOCKUP PREVIEW ── */
  .mockup {
    background: var(--surface2);
    border: 1px solid var(--border);
    border-radius: 4px;
    overflow: hidden;
    margin: 20px 0;
  }
  .mockup-bar {
    background: var(--surface);
    padding: 10px 16px;
    display: flex;
    align-items: center;
    gap: 6px;
    border-bottom: 1px solid var(--border);
  }
  .mockup-dot { width: 8px; height: 8px; border-radius: 50%; }
  .mockup-inner {
    padding: 24px;
    font-size: 13px;
    color: var(--muted);
    line-height: 1.6;
  }

  /* ── RESULT PREVIEW ── */
  .result-frame {
    border: 1px solid var(--accent);
    border-radius: 4px;
    overflow: hidden;
    margin: 20px 0;
  }
  .result-header {
    background: var(--accent);
    padding: 10px 16px;
    font-size: 12px;
    font-weight: 700;
    color: #0d0d0f;
    font-family: 'DM Mono', monospace;
    letter-spacing: 1px;
  }
  .result-body {
    padding: 24px;
    font-size: 14px;
    line-height: 1.7;
  }

  /* ── NAV BUTTONS ── */
  .step-nav {
    display: flex;
    gap: 12px;
    margin-top: 32px;
  }
  .btn-prev, .btn-next {
    padding: 12px 24px;
    border-radius: 2px;
    font-size: 14px;
    font-weight: 600;
    cursor: pointer;
    transition: all 0.2s;
    font-family: 'Pretendard', sans-serif;
    border: none;
  }
  .btn-next {
    background: var(--accent);
    color: #0d0d0f;
  }
  .btn-next:hover { background: #d4eb3a; }
  .btn-prev {
    background: transparent;
    color: var(--muted);
    border: 1px solid var(--border);
  }
  .btn-prev:hover { color: var(--text); border-color: var(--text); }

  /* ── SELF EVAL ── */
  .eval-grid {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 12px;
    margin: 20px 0;
  }
  .eval-item {
    background: var(--surface2);
    border: 1px solid var(--border);
    border-radius: 4px;
    padding: 16px;
    cursor: pointer;
    transition: all 0.2s;
    font-size: 13px;
    color: var(--muted);
  }
  .eval-item:hover { border-color: var(--accent); color: var(--text); }
  .eval-item.selected { border-color: var(--accent); background: rgba(232,255,71,0.05); color: var(--accent); }
  .eval-label { font-size: 11px; color: var(--muted); margin-bottom: 6px; font-family: 'DM Mono', monospace; }

  /* ── BADGE ── */
  .badge-area {
    text-align: center;
    padding: 40px;
    background: var(--surface);
    border: 1px solid var(--border);
    border-radius: 4px;
  }
  .badge-icon { font-size: 64px; margin-bottom: 16px; }
  .badge-title { font-family: 'Noto Serif KR', serif; font-size: 22px; font-weight: 700; margin-bottom: 8px; }
  .badge-sub { color: var(--muted); font-size: 14px; }

  /* ── COMPLETION STARS ── */
  .stars { color: var(--accent); font-size: 20px; letter-spacing: 4px; margin: 16px 0; }

  /* ── SCROLLBAR ── */
  ::-webkit-scrollbar { width: 4px; height: 4px; }
  ::-webkit-scrollbar-track { background: var(--bg); }
  ::-webkit-scrollbar-thumb { background: var(--border); border-radius: 2px; }

  /* ── RESPONSIVE ── */
  @media (max-width: 768px) {
    .container { grid-template-columns: 1fr; }
    .sidebar { display: none; }
    .content { padding: 24px; }
    .eval-grid { grid-template-columns: 1fr; }
    .overview-grid { grid-template-columns: 1fr 1fr; }
  }

  /* ── PROGRESS BAR ── */
  .progress-bar-wrap {
    height: 3px;
    background: var(--border);
    margin-bottom: 32px;
    border-radius: 2px;
    overflow: hidden;
  }
  .progress-bar-fill {
    height: 100%;
    background: var(--accent);
    border-radius: 2px;
    transition: width 0.4s ease;
  }

  .tag-row { display: flex; gap: 8px; flex-wrap: wrap; margin: 12px 0; }
  .tag { background: var(--tag-bg); border: 1px solid var(--border); font-size: 11px; padding: 3px 10px; border-radius: 2px; color: var(--muted); font-family: 'DM Mono', monospace; }

  .divider { border: none; border-top: 1px solid var(--border); margin: 24px 0; }

  .input-field {
    width: 100%;
    background: var(--surface2);
    border: 1px solid var(--border);
    border-radius: 4px;
    padding: 14px 16px;
    color: var(--text);
    font-size: 14px;
    font-family: 'Pretendard', sans-serif;
    transition: border-color 0.2s;
    resize: vertical;
    min-height: 80px;
    outline: none;
  }
  .input-field:focus { border-color: var(--accent); }
  .input-label { font-size: 12px; color: var(--muted); margin-bottom: 6px; display: block; }

  .generate-btn {
    background: var(--accent);
    color: #0d0d0f;
    border: none;
    padding: 12px 24px;
    font-size: 14px;
    font-weight: 700;
    border-radius: 2px;
    cursor: pointer;
    font-family: 'Pretendard', sans-serif;
    transition: all 0.2s;
    margin-top: 12px;
  }
  .generate-btn:hover { background: #d4eb3a; transform: translateY(-1px); }

  .output-area {
    display: none;
    background: var(--surface2);
    border: 1px solid var(--accent);
    border-radius: 4px;
    padding: 24px;
    margin-top: 16px;
    animation: fadeIn 0.4s ease;
  }
  .output-area.visible { display: block; }
  @keyframes fadeIn { from { opacity: 0; transform: translateY(8px); } to { opacity: 1; transform: translateY(0); } }

  .loading-dots::after {
    content: '...';
    animation: dots 1.2s infinite;
  }
  @keyframes dots {
    0% { content: '.'; }
    33% { content: '..'; }
    66% { content: '...'; }
  }
</style>
</head>
<body>

<!-- HEADER -->
<div class="header">
  <div class="header-tag">AX Training Lab · 2026</div>
  <h1>Lovable로 만드는<br><span>HR 앱 3분 실습</span></h1>
  <p class="header-sub">코드 없이, 프롬프트 하나로 — HR 담당자를 위한 AI 앱 빌딩 실전 가이드</p>
  <div class="header-meta">
    <div class="meta-chip"><span class="dot"></span>5가지 과제</div>
    <div class="meta-chip"><span class="dot"></span>단계별 실습</div>
    <div class="meta-chip"><span class="dot"></span>복사 가능한 프롬프트</div>
    <div class="meta-chip"><span class="dot"></span>실시간 결과 체험</div>
  </div>
</div>

<!-- CONTAINER -->
<div class="container">

  <!-- SIDEBAR -->
  <div class="sidebar">
    <div class="sidebar-label">학습 진행</div>
    <div class="mission-card">
      <div class="title">오늘의 미션</div>
