          <div class="badge-sub">회의록 자동화 도구를 직접 만들고 체험했습니다</div>
          <button class="btn-next" style="margin-top:20px" onclick="showTask('overview')">다른 과제 선택하기</button>
        </div>
        <div class="step-nav">
          <button class="btn-prev" onclick="goStep('t5',3)">← 이전</button>
          <button class="btn-next" onclick="completeTask('t5')">완료 ✓</button>
