function initQuiz() {
  state.quizAnswers = [];
  state.currentQ = 0;
  renderQuestion();
  document.getElementById('quiz-output').classList.remove('visible');
  document.getElementById('quiz-output').innerHTML = '';
}

function renderQuestion() {
  const container = document.getElementById('quiz-question-area');
  if(state.currentQ >= quizData.length) { showQuizResult(); return; }
  const q = quizData[state.currentQ];
  container.innerHTML = `
    <div style="margin-bottom:12px;">
      <div style="font-size:11px;color:var(--muted);font-family:'DM Mono',monospace;margin-bottom:8px;">Q${state.currentQ+1} / ${quizData.length}</div>
      <div style="background:var(--border);height:3px;border-radius:2px;margin-bottom:16px;overflow:hidden;">
        <div style="width:${((state.currentQ)/quizData.length)*100}%;height:100%;background:var(--accent);transition:width 0.3s;"></div>
      </div>
      <div style="font-size:16px;font-weight:600;margin-bottom:16px;">${q.q}</div>
      <div style="display:flex;flex-direction:column;gap:8px;">
        ${q.opts.map((o,i) => `
          <button onclick="answerQ(${i+1})" style="text-align:left;padding:12px 16px;background:var(--surface2);border:1px solid var(--border);border-radius:4px;color:var(--text);font-size:14px;cursor:pointer;font-family:'Pretendard',sans-serif;transition:all 0.15s;"
            onmouseover="this.style.borderColor='var(--accent)';this.style.color='var(--accent)'"
            onmouseout="this.style.borderColor='var(--border)';this.style.color='var(--text)'">
            <span style="font-family:'DM Mono',monospace;font-size:11px;color:var(--muted);margin-right:10px;">${String.fromCharCode(64+i+1)}</span>${o}
          </button>
        `).join('')}
      </div>
    </div>
  `;
}

function answerQ(score) {
  state.quizAnswers.push(score);
  state.currentQ++;
  renderQuestion();
}

function showQuizResult() {
  const total = state.quizAnswers.reduce((a,b)=>a+b,0);
  const lv = levelMap.find(l => total >= l.score[0] && total <= l.score[1]) || levelMap[levelMap.length-1];
  document.getElementById('quiz-question-area').innerHTML = '';
  const out = document.getElementById('quiz-output');
  out.innerHTML = `
    <div style="text-align:center;">
      <div style="font-size:11px;color:var(--muted);margin-bottom:4px;font-family:'DM Mono',monospace;">총점 ${total} / 20</div>
      <div style="font-size:24px;font-weight:700;color:var(--accent);margin:12px 0;">${lv.level}</div>
      <div style="font-size:14px;color:var(--muted);margin-bottom:20px;">${lv.desc}</div>
      <hr style="border-color:var(--border);margin:16px 0;">
      <div style="text-align:left;">
        <div style="font-size:12px;color:var(--accent2);margin-bottom:8px;font-family:'DM Mono',monospace;">추천 다음 액션</div>
        ${lv.next.map(n=>`<div style="font-size:13px;color:var(--muted);padding:8px 0;border-bottom:1px solid var(--border);">→ ${n}</div>`).join('')}
      </div>
      <button onclick="initQuiz()" style="margin-top:16px;background:transparent;border:1px solid var(--border);color:var(--muted);padding:8px 16px;border-radius:2px;cursor:pointer;font-family:'Pretendard',sans-serif;font-size:13px;">다시 진단하기</button>
    </div>
  `;
  out.classList.add('visible');
}

// ── TASK 5: MINUTES ──
const sampleMinutes = `[2026년 3월 6일 AX 추진팀 주간 미팅]
참석: 김팀장, 이대리, 박사원, 최주임

1. Vibe-Coding 교육 커리큘럼 관련
- 이대리가 3월 14일까지 1차 초안 작성 예정
- 박사원은 Lovable 실습 예제 5개 이번 주 금요일까지 준비
- 최주임이 수강 신청 시스템 연동 여부 다음 주 수요일까지 확인

2. Pulse Check 시스템
- 김팀장이 3월 말까지 경영진 보고 자료 준비
- 이대리가 설문 문항 초안 검토 후 이번 주 중 공유

3. 기타
- 팀 전체 AI 툴 체험 세션 일정 미정 (담당자 미정)`;

function loadSampleMinutes() {
  document.getElementById('minutes-input').value = sampleMinutes;
}

function extractActions() {
  const text = document.getElementById('minutes-input').value;
  if(!text.trim()) { alert('회의록을 입력해주세요.'); return; }

  const actions = [];
  const lines = text.split('\n');
  const patterns = [
    {re:/(.+?)(이|가)\s+(.+?)(까지|예정|할 예정|준비|작성|확인|공유|검토|진행)/g, type:'task'},
  ];

  lines.forEach(line => {
    const trimmed = line.trim();
    if(!trimmed || trimmed.startsWith('[') || trimmed.startsWith('참석')) return;

    let assignee = '미정';
    let task = trimmed.replace(/^[-\d\.]\s*/,'');
    let due = '미정';
    let priority = 'Medium';

    const personMatch = trimmed.match(/^[-]?\s*([가-힣]{2,4})(팀장|대리|사원|주임|과장|차장|부장)?/);
    if(personMatch) assignee = personMatch[1] + (personMatch[2]||'');

    const dueMatch = trimmed.match(/(\d+월\s*\d+일|이번\s*주\s*[가-힣]+|다음\s*주\s*[가-힣]+|[가-힣]+\s*말|[가-힣]+\s*중)/);
    if(dueMatch) due = dueMatch[0];

    if(trimmed.includes('경영진') || trimmed.includes('보고') || trimmed.includes('완료')) priority = 'High';
    if(trimmed.includes('미정') || trimmed.includes('검토')) priority = 'Low';

    if(trimmed.includes('-') || trimmed.includes('예정') || trimmed.includes('준비') || trimmed.includes('작성')) {
      actions.push({task: task.substring(0,50), assignee, due, priority});
    }
  });

  if(actions.length === 0) {
    actions.push({task:'자동 추출 결과 없음 — 샘플 데이터를 사용해보세요', assignee:'미정', due:'미정', priority:'Low'});
  }

  const pColor = {High:'#ff6b6b',Medium:'#e8ff47',Low:'#47ff8a'};
  const out = document.getElementById('minutes-output');
  out.innerHTML = `
    <div style="font-size:12px;color:var(--accent);margin-bottom:12px;font-family:'DM Mono',monospace;">✓ 액션아이템 ${actions.length}개 추출</div>
    <div style="overflow-x:auto;">
      <table style="width:100%;border-collapse:collapse;font-size:13px;">
        <thead>
          <tr style="border-bottom:1px solid var(--border);">
            <th style="text-align:left;padding:8px 12px;color:var(--muted);font-weight:600;">할 일</th>
            <th style="text-align:left;padding:8px 12px;color:var(--muted);font-weight:600;">담당자</th>
            <th style="text-align:left;padding:8px 12px;color:var(--muted);font-weight:600;">기한</th>
            <th style="text-align:left;padding:8px 12px;color:var(--muted);font-weight:600;">우선순위</th>
          </tr>
        </thead>
        <tbody>
          ${actions.map(a => `
            <tr style="border-bottom:1px solid var(--border);">
              <td style="padding:10px 12px;">${a.task}</td>
              <td style="padding:10px 12px;${a.assignee==='미정'?'color:#ff6b6b':''}">${a.assignee}</td>
              <td style="padding:10px 12px;color:var(--muted);">${a.due}</td>
              <td style="padding:10px 12px;"><span style="font-size:11px;font-weight:700;color:${pColor[a.priority]};border:1px solid ${pColor[a.priority]};padding:2px 8px;border-radius:2px;font-family:'DM Mono',monospace;">${a.priority}</span></td>
            </tr>
          `).join('')}
        </tbody>
      </table>
    </div>
  `;
  out.classList.add('visible');
}

// ── INIT ──
document.querySelectorAll('[data-task]').forEach(btn => {
  btn.addEventListener('click', () => showTask(btn.dataset.task));
});
</script>
</body>
</html>
", "filename": "/mnt/user-data/outputs/lovable-hr-lab.html"}

